  isOpen, onClose, cart, onUpdateQuantity, onRemove, activeCoupon, setActiveCoupon 
}) => {
  const [couponCode, setCouponCode] = useState('');
  const [couponError, setCouponError] = useState('');
  const [isApplying, setIsApplying] = useState(false);

  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const discount = activeCoupon 
    ? (activeCoupon.discount_type === 'percentage' 
        ? subtotal * (activeCoupon.value / 100) 
        : activeCoupon.value)
    : 0;

  const total = Math.max(0, subtotal - discount);

  const handleApplyCoupon = async () => {
    setIsApplying(true);
    setCouponError('');

    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 800));

    const found = MOCK_COUPONS.find(c => c.code.toUpperCase() === couponCode.toUpperCase());

    if (found) {
      if (subtotal < found.min_spend) {
        setCouponError(`Min spend for this coupon is $${found.min_spend}`);
      } else {
        setActiveCoupon(found);
        setCouponCode('');
      }
    } else {
      setCouponError('Invalid coupon code');
    }
    setIsApplying(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] overflow-hidden">
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={onClose} />

      <div className={`absolute inset-y-0 right-0 max-w-md w-full bg-white shadow-2xl transform transition-transform duration-500 ease-out flex flex-col ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-6 border-b border-slate-100">
          <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
            Your Cart <span className="text-slate-400 font-medium text-sm">({cart.length} items)</span>
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-all">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-center">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                <ShoppingBag className="w-10 h-10 text-slate-300" />
              </div>
              <p className="text-slate-500 font-medium">Your cart is empty</p>
              <button onClick={onClose} className="mt-4 text-blue-500 font-semibold hover:underline">Start Shopping</button>
            </div>
          ) : (
            cart.map((item) => (
              <div key={item.id} className="flex gap-4 group">
                <div className="w-20 h-20 rounded-xl overflow-hidden bg-slate-50 border border-slate-100 flex-shrink-0">
                  <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 flex flex-col justify-between py-1">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold text-slate-900 text-sm leading-tight mb-1">{item.name}</h4>
                      <p className="text-xs text-slate-400">{item.category}</p>
                    </div>
                    <span className="font-bold text-slate-900 text-sm">${(item.price * item.quantity).toFixed(2)}</span>
                  </div>
                  <div className="flex items-center justify-between mt-2">
                    <div className="flex items-center border border-slate-100 rounded-lg p-1">
                      <button 
                        onClick={() => onUpdateQuantity(item.id, -1)}
                        className="p-1 hover:bg-slate-50 rounded transition-colors"
                      >
                        <Minus className="w-3 h-3 text-slate-400" />
                      </button>
                      <span className="w-8 text-center text-xs font-bold text-slate-900">{item.quantity}</span>
                      <button 
                        onClick={() => onUpdateQuantity(item.id, 1)}
                        className="p-1 hover:bg-slate-50 rounded transition-colors"
                      >
                        <Plus className="w-3 h-3 text-slate-400" />
                      </button>
                    </div>
                    <button 
                      onClick={() => onRemove(item.id)}
                      className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 bg-slate-50/50 border-t border-slate-100 space-y-4">
            {/* Coupon Section */}
            {!activeCoupon ? (
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Add Coupon Code</label>
                <div className="flex gap-2">
                  <div className="relative flex-1">
                    <input 
                      type="text" 
                      placeholder="e.g. SAVE20"
                      value={couponCode}
                      onChange={(e) => setCouponCode(e.target.value)}
                      className={`w-full pl-10 pr-4 py-3 bg-white border ${couponError ? 'border-red-200 bg-red-50' : 'border-slate-200'} rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all`}
                    />
                    <Ticket className={`absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 ${couponError ? 'text-red-400' : 'text-slate-400'}`} />
                  </div>
                  <button 
                    onClick={handleApplyCoupon}
                    disabled={!couponCode || isApplying}
                    className="px-6 bg-slate-900 text-white rounded-xl font-semibold text-sm hover:bg-slate-800 disabled:bg-slate-300 transition-all flex items-center justify-center min-w-[90px]"
                  >
                    {isApplying ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Apply'}
                  </button>
                </div>
                {couponError && (
                  <p className="text-red-500 text-[11px] font-medium flex items-center gap-1">
                    <AlertCircle className="w-3 h-3" /> {couponError}
                  </p>
                )}
              </div>
            ) : (
              <div className="flex items-center justify-between p-3 bg-blue-50 border border-blue-100 rounded-xl animate-in fade-in slide-in-from-top-1">
                <div className="flex items-center gap-2">
                  <CheckCircle2 className="w-5 h-5 text-blue-500" />
                  <div>
                    <p className="text-blue-900 text-xs font-bold">{activeCoupon.code} Applied</p>
                    <p className="text-blue-600 text-[10px]">{activeCoupon.value}{activeCoupon.discount_type === 'percentage' ? '%' : '$'} Discount</p>
                  </div>
                </div>
                <button 
                  onClick={() => setActiveCoupon(null)}
                  className="text-blue-400 hover:text-blue-600 p-1.5"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            )}

            <div className="space-y-3">
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Subtotal</span>
                <span className="font-bold text-slate-900">${subtotal.toFixed(2)}</span>
              </div>
              {activeCoupon && (
                <div className="flex justify-between text-sm text-blue-600 font-medium">
                  <span>Coupon Discount</span>
                  <span>-${discount.toFixed(2)}</span>
                </div>
              )}
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Shipping</span>
                <span className="text-green-600 font-medium">Calculated at checkout</span>
              </div>
              <div className="pt-3 border-t border-slate-200 flex justify-between items-center">
                <span className="text-lg font-bold text-slate-900">Total</span>
                <span className="text-2xl font-bold text-slate-900 tracking-tight">${total.toFixed(2)}</span>
              </div>
            </div>

            <button className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 flex items-center justify-center gap-3 group">
              Complete Purchase <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

