import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Minus, Plus, Trash2, Ticket, ArrowRight, CheckCircle2, AlertCircle, ShoppingBag, CreditCard } from 'lucide-react';
import { CartItem, Coupon } from '../types';
import { MOCK_COUPONS } from '../constants';

interface CartDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  onUpdateQuantity: (id: number, delta: number) => void;
  onRemove: (id: number) => void;
  activeCoupon: Coupon | null;
  setActiveCoupon: (c: Coupon | null) => void;
}

const CartDrawer: React.FC<CartDrawerProps> = ({ 
  isOpen, onClose, cart, onUpdateQuantity, onRemove, activeCoupon, setActiveCoupon 
}) => {
  const [couponCode, setCouponCode] = useState('');
  const [couponError, setCouponError] = useState('');
  const [isApplying, setIsApplying] = useState(false);

  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const discount = activeCoupon 
    ? (activeCoupon.discount_type === 'percentage' 
        ? subtotal * (activeCoupon.value / 100) 
        : activeCoupon.value)
    : 0;
  const total = Math.max(0, subtotal - discount);

  const handleApplyCoupon = async () => {
    setIsApplying(true);
    setCouponError('');
    await new Promise(resolve => setTimeout(resolve, 800));
    const found = MOCK_COUPONS.find(c => c.code.toUpperCase() === couponCode.toUpperCase());
    if (found) {
      if (subtotal < found.min_spend) {
        setCouponError(`Min spend for this coupon is $${found.min_spend}`);
      } else {
        setActiveCoupon(found);
        setCouponCode('');
      }
    } else {
      setCouponError('Invalid coupon code');
    }
    setIsApplying(false);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-slate-950/40 backdrop-blur-md transition-opacity" 
            onClick={onClose} 
          />

          <motion.div 
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="absolute inset-y-0 right-0 max-w-lg w-full bg-white shadow-2xl flex flex-col"
          >
            {/* Header */}
            <div className="flex items-center justify-between p-8 border-b border-slate-50">
              <div>
                <h2 className="luxury-serif text-3xl font-bold text-slate-950">Maison Bag</h2>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Curation Phase: Active</p>
              </div>
              <button 
                onClick={onClose} 
                className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-all"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            {/* Cart Items */}
            <div className="flex-1 overflow-y-auto p-8 space-y-8 scroll-smooth">
              {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-center py-20">
                  <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mb-6 text-slate-200">
                    <ShoppingBag className="w-12 h-12" />
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-2">The bag is empty</h3>
                  <p className="text-slate-400 max-w-xs mx-auto mb-8 font-light">Your next masterpiece is waiting in our latest curation.</p>
                  <button onClick={onClose} className="px-10 py-4 bg-slate-950 text-white rounded-full font-bold hover:bg-slate-900 transition-all active:scale-95 shadow-lg">
                    Browse Collection
                  </button>
                </div>
              ) : (
                cart.map((item, idx) => (
                  <motion.div 
                    key={item.id} 
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: idx * 0.1 }}
                    className="flex gap-6 group"
                  >
                    <div className="w-24 h-32 rounded-2xl overflow-hidden bg-slate-50 border border-slate-100 flex-shrink-0">
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                    </div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div className="flex justify-between items-start">
                        <div>
                          <h4 className="font-bold text-slate-950 text-base mb-1 hover:text-blue-600 transition-colors cursor-pointer">{item.name}</h4>
                          <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">{item.category}</p>
                        </div>
                        <span className="font-bold text-slate-950 text-base">${(item.price * item.quantity).toFixed(2)}</span>
                      </div>

                      <div className="flex items-center justify-between">
                        <div className="flex items-center bg-slate-50 rounded-full px-2 py-1">
                          <button 
                            onClick={() => onUpdateQuantity(item.id, -1)}
                            className="w-8 h-8 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-full transition-all text-slate-400 hover:text-slate-900"
                          >
                            <Minus className="w-4 h-4" />
                          </button>
                          <span className="w-10 text-center text-sm font-black text-slate-950">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.id, 1)}
                            className="w-8 h-8 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-full transition-all text-slate-400 hover:text-slate-900"
                          >
                            <Plus className="w-4 h-4" />
                          </button>
                        </div>
                        <button 
                          onClick={() => onRemove(item.id)}
                          className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-slate-300 hover:text-rose-500 transition-all"
                        >
                          <Trash2 className="w-4 h-4" /> Remove
                        </button>
                      </div>
                    </div>
                  </motion.div>
                ))
              )}
            </div>

            {/* Footer / Summary */}
            {cart.length > 0 && (
              <div className="p-8 bg-slate-50/80 backdrop-blur-xl border-t border-slate-100 space-y-6">
                {!activeCoupon ? (
                  <div className="space-y-3">
                    <div className="flex gap-2">
                      <div className="relative flex-1 group">
                        <input 
                          type="text" 
                          placeholder="Promo Code"
                          value={couponCode}
                          onChange={(e) => setCouponCode(e.target.value)}
                          className={`w-full pl-12 pr-4 py-4 bg-white border ${couponError ? 'border-red-200 bg-red-50' : 'border-slate-100'} rounded-2xl text-sm font-semibold focus:outline-none focus:ring-2 focus:ring-slate-950/5 transition-all shadow-sm`}
                        />
                        <Ticket className={`absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 ${couponError ? 'text-red-400' : 'text-slate-300'}`} />
                      </div>
                      <button 
                        onClick={handleApplyCoupon}
                        disabled={!couponCode || isApplying}
                        className="px-8 bg-slate-950 text-white rounded-2xl font-bold text-sm hover:bg-slate-900 disabled:bg-slate-200 transition-all flex items-center justify-center min-w-[100px]"
                      >
                        {isApplying ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Apply'}
                      </button>
                    </div>
                    {couponError && (
                      <p className="text-red-500 text-[11px] font-bold flex items-center gap-1 ml-1">
                        <AlertCircle className="w-3.5 h-3.5" /> {couponError}
                      </p>
                    )}
                  </div>
                ) : (
                  <motion.div 
                    initial={{ scale: 0.95, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    className="flex items-center justify-between p-4 bg-blue-600 text-white rounded-2xl shadow-xl shadow-blue-500/20"
                  >
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center">
                        <CheckCircle2 className="w-6 h-6" />
                      </div>
                      <div>
                        <p className="text-xs font-black tracking-widest uppercase text-white/70 leading-none mb-1">Coupon Active</p>
                        <p className="text-sm font-bold leading-none">{activeCoupon.code} (-{activeCoupon.value}{activeCoupon.discount_type === 'percentage' ? '%' : '$'})</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => setActiveCoupon(null)}
                      className="p-2 hover:bg-white/10 rounded-full transition-all"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  </motion.div>
                )}

                <div className="space-y-4 py-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500 font-medium">Subtotal</span>
                    <span className="font-bold text-slate-950">${subtotal.toFixed(2)}</span>
                  </div>
                  {activeCoupon && (
                    <div className="flex justify-between text-sm font-bold text-blue-600">
                      <span>Maison Privilege Discount</span>
                      <span>-${discount.toFixed(2)}</span>
                    </div>
                  )}
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500 font-medium">Global Express Delivery</span>
                    <span className="text-emerald-600 font-bold uppercase text-[10px] tracking-widest">Complimentary</span>
                  </div>
                  <div className="pt-6 border-t border-slate-200 flex justify-between items-end">
                    <div>
                      <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-1">Final Investment</p>
                      <span className="text-4xl font-bold text-slate-950 tracking-tighter">${total.toFixed(2)}</span>
                    </div>
                    <div className="flex flex-col items-end gap-1">
                      <div className="flex gap-1">
                        <div className="w-8 h-5 rounded bg-slate-200" />
                        <div className="w-8 h-5 rounded bg-slate-200" />
                        <div className="w-8 h-5 rounded bg-slate-200" />
                      </div>
                      <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Secure Checkout</span>
                    </div>
                  </div>
                </div>

                <button className="group w-full py-5 bg-slate-950 text-white rounded-3xl font-black text-lg hover:bg-slate-900 transition-all shadow-[0_20px_50px_rgba(0,0,0,0.15)] flex items-center justify-center gap-3 active:scale-[0.98]">
                  <CreditCard className="w-6 h-6" /> Proceed to Secure Checkout <ArrowRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                </button>
              </div>
            )}
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

