import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Minus, Plus, Trash2, Ticket, ArrowRight, CheckCircle2, AlertCircle, ShoppingBag, CreditCard, Sparkles } from 'lucide-react';
import { CartItem, Coupon } from '../types';
import { MOCK_COUPONS } from '../constants';

interface CartDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  onUpdateQuantity: (id: number, delta: number) => void;
  onRemove: (id: number) => void;
  onClear: () => void;
  activeCoupon: Coupon | null;
  setActiveCoupon: (c: Coupon | null) => void;
}

const CartDrawer: React.FC<CartDrawerProps> = ({ 
  isOpen, onClose, cart, onUpdateQuantity, onRemove, onClear, activeCoupon, setActiveCoupon 
}) => {
  const [couponCode, setCouponCode] = useState('');
  const [couponError, setCouponError] = useState('');
  const [isApplying, setIsApplying] = useState(false);
  const [isCheckingOut, setIsCheckingOut] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const discount = activeCoupon 
    ? (activeCoupon.discount_type === 'percentage' 
        ? subtotal * (activeCoupon.value / 100) 
        : activeCoupon.value)
    : 0;
  const total = Math.max(0, subtotal - discount);

  const handleApplyCoupon = async () => {
    setIsApplying(true);
    setCouponError('');
    await new Promise(resolve => setTimeout(resolve, 800));
    const found = MOCK_COUPONS.find(c => c.code.toUpperCase() === couponCode.toUpperCase());
    if (found) {
      if (subtotal < found.min_spend) {
        setCouponError(`Min spend for this coupon is $${found.min_spend}`);
      } else {
        setActiveCoupon(found);
        setCouponCode('');
      }
    } else {
      setCouponError('Invalid coupon code');
    }
    setIsApplying(false);
  };

  const handleCheckout = async () => {
    setIsCheckingOut(true);
    // Simulate payment processing
    await new Promise(resolve => setTimeout(resolve, 2500));
    setIsCheckingOut(false);
    setOrderComplete(true);
    setTimeout(() => {
      onClear();
      setOrderComplete(false);
      onClose();
    }, 4000);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-slate-950/40 backdrop-blur-md transition-opacity" 
            onClick={onClose} 
          />

          <motion.div 
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="absolute inset-y-0 right-0 max-w-lg w-full bg-white shadow-2xl flex flex-col"
          >
            {orderComplete ? (
              <div className="flex-1 flex flex-col items-center justify-center p-8 text-center bg-slate-900 text-white overflow-hidden relative">
                <motion.div 
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center mb-8 shadow-[0_0_50px_rgba(34,197,94,0.4)]"
                >
                  <CheckCircle2 className="w-12 h-12" />
                </motion.div>
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.3 }}
                >
                  <h2 className="luxury-serif text-4xl font-bold mb-4">Maison Order Confirmed</h2>
                  <p className="text-slate-400 text-lg font-light max-w-sm mx-auto">
                    Your acquisition is being prepared with clinical precision. We will notify you once transit begins.
                  </p>
                </motion.div>
                <motion.div 
                  className="absolute inset-0 pointer-events-none"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: [0, 1, 0] }}
                  transition={{ duration: 2, repeat: Infinity }}
                >
                  <Sparkles className="w-full h-full opacity-5" />
                </motion.div>
              </div>
            ) : (
              <>
                {/* Header */}
                <div className="flex items-center justify-between p-8 border-b border-slate-50">
                  <div>
                    <h2 className="luxury-serif text-3xl font-bold text-slate-950">Maison Bag</h2>
                    <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Curation Phase: Active</p>
                  </div>
                  <button 
                    onClick={onClose} 
                    className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-all"
                  >
                    <X className="w-6 h-6" />
                  </button>
                </div>

                {/* Cart Items */}
                <div className="flex-1 overflow-y-auto p-8 space-y-8 scroll-smooth">
                  {cart.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-center py-20">
