                          >
                            {isApplying ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Apply'}
                          </button>
                        </div>
                        {couponError && (
                          <p className="text-red-500 text-[11px] font-bold flex items-center gap-1 ml-1">
                            <AlertCircle className="w-3.5 h-3.5" /> {couponError}
                          </p>
                        )}
                      </div>
                    ) : (
                      <motion.div 
                        initial={{ scale: 0.95, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        className="flex items-center justify-between p-4 bg-blue-600 text-white rounded-2xl shadow-xl shadow-blue-500/20"
                      >
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center">
                            <CheckCircle2 className="w-6 h-6" />
                          </div>
                          <div>
                            <p className="text-xs font-black tracking-widest uppercase text-white/70 leading-none mb-1">Coupon Active</p>
                            <p className="text-sm font-bold leading-none">{activeCoupon.code} (-{activeCoupon.value}{activeCoupon.discount_type === 'percentage' ? '%' : '$'})</p>
                          </div>
                        </div>
                        <button 
                          onClick={() => setActiveCoupon(null)}
                          className="p-2 hover:bg-white/10 rounded-full transition-all"
                        >
                          <X className="w-4 h-4" />
                        </button>
                      </motion.div>
                    )}

                    <div className="space-y-4 py-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-500 font-medium">Subtotal</span>
                        <span className="font-bold text-slate-950">${subtotal.toFixed(2)}</span>
                      </div>
                      {activeCoupon && (
                        <div className="flex justify-between text-sm font-bold text-blue-600">
                          <span>Maison Privilege Discount</span>
                          <span>-${discount.toFixed(2)}</span>
                        </div>
                      )}
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-500 font-medium">Global Express Delivery</span>
                        <span className="text-emerald-600 font-bold uppercase text-[10px] tracking-widest">Complimentary</span>
                      </div>
                      <div className="pt-6 border-t border-slate-200 flex justify-between items-end">
                        <div>
                          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-1">Final Investment</p>
                          <span className="text-4xl font-bold text-slate-950 tracking-tighter">${total.toFixed(2)}</span>
                        </div>
                        <div className="flex flex-col items-end gap-1">
                          <div className="flex gap-1">
                            <div className="w-8 h-5 rounded bg-slate-200" />
                            <div className="w-8 h-5 rounded bg-slate-200" />
                            <div className="w-8 h-5 rounded bg-slate-200" />
                          </div>
                          <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Secure Checkout</span>
                        </div>
                      </div>
                    </div>

                    <button 
                      onClick={handleCheckout}
                      disabled={isCheckingOut}
                      className="group w-full py-5 bg-slate-950 text-white rounded-3xl font-black text-lg hover:bg-slate-900 transition-all shadow-[0_20px_50px_rgba(0,0,0,0.15)] flex items-center justify-center gap-3 active:scale-[0.98] disabled:bg-slate-800"
                    >
                      {isCheckingOut ? (
                        <div className="flex items-center gap-3">
                          <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin" />
                          Authenticating...
                        </div>
                      ) : (
                        <>
                          <CreditCard className="w-6 h-6" /> Proceed to Secure Checkout <ArrowRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                        </>
                      )}
                    </button>
                  </div>
                )}
              </>
            )}
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

