import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowRight, Zap, Star, ShieldCheck, Truck, Search, X } from 'lucide-react';
import { Product, CartItem, Coupon } from './types';
import Navbar from './components/Navbar';
import ProductList from './components/ProductList';
import CartDrawer from './components/CartDrawer';
import ProductModal from './components/ProductModal';
import { PRODUCTS } from './constants';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCoupon, setActiveCoupon] = useState<Coupon | null>(null);
  const [isScrolled, setIsScrolled] = useState(false);
  const [activeCategory, setActiveCategory] = useState('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [showSearch, setShowSearch] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => {
      const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           p.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchQuery]);

  const categories = useMemo(() => ['All', ...Array.from(new Set(PRODUCTS.map(p => p.category)))], []);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
    setSelectedProduct(null);
  };

  const removeFromCart = (id: number) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: number, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  return (
    <div className="min-h-screen bg-[#FDFDFD]">
      <Navbar 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} 
        onCartClick={() => setIsCartOpen(true)} 
        onSearchClick={() => setShowSearch(true)}
        isScrolled={isScrolled}
      />

      <AnimatePresence>
        {showSearch && (
          <motion.div 
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="fixed inset-x-0 top-0 z-[100] bg-white p-6 shadow-2xl border-b border-slate-100"
          >
            <div className="max-w-4xl mx-auto flex items-center gap-4">
              <Search className="w-6 h-6 text-slate-400" />
              <input 
                autoFocus
                type="text" 
                placeholder="Find your next signature look..." 
                className="flex-1 text-2xl font-light focus:outline-none placeholder:text-slate-300"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button onClick={() => setShowSearch(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="w-6 h-6" />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <main className="pt-24 pb-24">
        {/* Modern Lifestyle Hero */}
        <div className="max-w-[1440px] mx-auto px-6 mb-24">
          <motion.section 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 1.2 }}
            className="relative h-[80vh] min-h-[600px] overflow-hidden rounded-[3rem] bg-slate-950"
          >
            {/* Split Hero Layout */}
            <div className="absolute inset-0 flex flex-col md:flex-row">
              <div className="w-full md:w-1/2 h-full relative overflow-hidden">
                <img 
                  src="https://images.unsplash.com/photo-1516762689617-e1cffcef479d?q=80&w=2022&auto=format&fit=crop" 
                  className="w-full h-full object-cover scale-105 animate-subtle-zoom opacity-70"
                  alt="Lifestyle Model"
                />
              </div>
              <div className="hidden md:block w-1/2 h-full relative overflow-hidden">
                <img 
                  src="https://images.unsplash.com/photo-1539109136881-3be0616acf4b?q=80&w=1974&auto=format&fit=crop" 
                  className="w-full h-full object-cover scale-105 opacity-60"
                  alt="Product Close-up"
                />
              </div>
            </div>

            <div className="absolute inset-0 bg-gradient-to-r from-slate-950 via-slate-950/40 to-transparent z-10" />

            <div className="relative z-20 h-full flex items-center px-12 md:px-24">
              <div className="max-w-xl">
                <motion.div
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.5 }}
                  className="flex items-center gap-3 mb-6"
                >
                  <span className="w-12 h-[1px] bg-blue-500"></span>
                  <span className="text-blue-400 font-black uppercase tracking-[0.3em] text-[10px]">Lifestyle Maison</span>
                </motion.div>

                <motion.h1 
                  initial={{ opacity: 0, y: 30 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.7, duration: 0.8 }}
                  className="luxury-serif text-5xl md:text-7xl font-bold text-white mb-8 tracking-tight leading-[1.05]"
                >
                  Premium <br/>Essentials for <br/><span className="italic font-normal text-slate-300">Modern Life</span>
                </motion.h1>

                <motion.p 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.9, duration: 0.8 }}
                  className="text-slate-300 text-lg md:text-xl mb-12 font-light leading-relaxed max-w-md"
                >
                  Sophisticated basics designed for endurance. Ethical craftsmanship meets architectural precision.
                </motion.p>

                <motion.div 
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 1.1, duration: 0.8 }}
                  className="flex flex-wrap gap-6"
                >
                  <button 
                    onClick={() => document.getElementById('catalog')?.scrollIntoView({ behavior: 'smooth' })}
                    className="group relative px-10 py-5 bg-white text-slate-950 rounded-full font-black text-sm uppercase tracking-widest transition-all hover:scale-105 hover:shadow-[0_20px_50px_rgba(255,255,255,0.15)] flex items-center gap-3"
                  >
                    Explore Shop <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                  </button>
                </motion.div>
              </div>
            </div>
          </motion.section>
        </div>

        {/* Feature Grid */}
        <section className="max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-3 gap-16 mb-40">
          {[
            { title: "Long-Staple Cotton", desc: "We exclusively use 100% premium cotton for unmatched breathability and lasting softness." },
            { title: "Eco-Conscious Dyeing", desc: "Our low-impact dyeing process preserves the environment while maintaining vibrant color depth." },
            { title: "Precision Tailoring", desc: "Each garment is cut and stitched to a refined standard that ensures a lifetime of wear." }
          ].map((item, idx) => (
            <motion.div 
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              className="text-center"
            >
              <h3 className="text-sm font-black uppercase tracking-widest text-slate-950 mb-4">{item.title}</h3>
              <p className="text-slate-500 font-light text-base leading-relaxed">{item.desc}</p>
            </motion.div>
          ))}
        </section>

        {/* Product Catalog Header */}
        <div id="catalog" className="max-w-7xl mx-auto px-6 mb-16 scroll-mt-32">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-12 border-b border-slate-100 pb-12">
            <div>
              <h2 className="luxury-serif text-4xl md:text-6xl font-bold text-slate-950 mb-4">The Essentials</h2>
              <p className="text-slate-400 font-light text-lg">Curated drops for the discerning lifestyle.</p>
            </div>
            <div className="flex flex-wrap gap-3">
              {categories.map((cat) => (
                <button 
                  key={cat} 
                  onClick={() => setActiveCategory(cat)}
                  className={`px-8 py-3 rounded-full text-[11px] font-black uppercase tracking-widest transition-all border ${activeCategory === cat ? 'bg-slate-950 text-white border-slate-950 shadow-xl' : 'text-slate-400 border-slate-100 hover:border-slate-300 hover:text-slate-900'}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>
        </div>

        <section className="max-w-7xl mx-auto px-6">
          <ProductList 
            products={filteredProducts} 
            onAddToCart={addToCart} 
            onProductClick={(p) => setSelectedProduct(p)}
          />
        </section>
      </main>

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart} 
        onUpdateQuantity={updateQuantity}
        onRemove={removeFromCart}
        onClear={clearCart}
        activeCoupon={activeCoupon}
        setActiveCoupon={setActiveCoupon}
      />

      <AnimatePresence>
        {selectedProduct && (
          <ProductModal 
            product={selectedProduct} 
            onClose={() => setSelectedProduct(null)} 
            onAddToCart={addToCart}
          />
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

