          ref={containerRef}
          onMouseMove={handleMouseMove}
          onMouseEnter={() => setShowMagnifier(true)}
          onMouseLeave={() => setShowMagnifier(false)}
          className="relative lg:w-3/5 bg-[#F9F9F9] overflow-hidden cursor-none group h-[500px] lg:h-auto"
        >
          <img 
            src={product.image} 
            alt={product.name} 
            className="w-full h-full object-cover select-none pointer-events-none"
          />

          {/* Magnifying Glass Lens */}
          <AnimatePresence>
            {showMagnifier && (
              <motion.div
                initial={{ opacity: 0, scale: 0 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0 }}
                transition={{ type: 'spring', damping: 25, stiffness: 250 }}
                style={{
                  position: 'absolute',
                  left: cursorPos.x - magnifierSize / 2,
                  top: cursorPos.y - magnifierSize / 2,
                  width: magnifierSize,
                  height: magnifierSize,
                  borderRadius: '50%',
                  pointerEvents: 'none',
                  border: '4px solid white',
                  boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)',
                  backgroundColor: '#fff',
                  backgroundImage: `url(${product.image})`,
                  backgroundRepeat: 'no-repeat',
                  backgroundSize: `${100 * zoomLevel}% ${100 * zoomLevel}%`,
                  backgroundPosition: `${magnifierPos.x}% ${magnifierPos.y}%`,
                  zIndex: 50
                }}
              />
            )}
          </AnimatePresence>

          {/* Static UI Overlay */}
          <div className="absolute inset-0 bg-gradient-to-t from-black/20 via-transparent to-transparent pointer-events-none" />

          <div className="absolute top-8 left-8 flex flex-col gap-4">
            <motion.div 
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className="bg-white/90 backdrop-blur-md px-5 py-3 rounded-2xl shadow-lg border border-white/20"
            >
              <div className="flex items-center gap-3 text-slate-900">
                <Search className="w-4 h-4" />
                <span className="text-[10px] font-black uppercase tracking-[0.2em]">
                  Hover to Magnify
                </span>
              </div>
            </motion.div>
          </div>

          {!showMagnifier && (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-3 p-2 bg-white/10 backdrop-blur-xl rounded-full border border-white/20"
            >
              {[1, 2, 3].map((i) => (
                <div key={i} className={`w-2 h-2 rounded-full transition-all duration-500 ${i === 1 ? 'bg-white' : 'bg-white/30'}`} />
              ))}
            </motion.div>
          )}
        </div>

        {/* Info Section */}
        <div className="lg:w-2/5 p-8 md:p-16 overflow-y-auto bg-white flex flex-col border-l border-slate-50">
          <div className="flex-1 space-y-12">
            <div className="space-y-6">
              <div className="flex items-center gap-4">
                <span className="px-4 py-1.5 bg-blue-50 text-blue-600 text-[10px] font-black uppercase tracking-[0.2em] rounded-full">
                  {product.category}
                </span>
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" /> In Stock
                </span>
              </div>
              <h2 className="luxury-serif text-4xl md:text-5xl font-bold text-slate-950 leading-tight tracking-tight">
                {product.name}
              </h2>
              <div className="flex items-center gap-2 text-amber-400">
                {[...Array(5)].map((_, i) => <Star key={i} className="w-4 h-4 fill-current" />)}
                <span className="text-slate-400 text-sm ml-3 font-medium tracking-wide">4.9 (124 reviews)</span>
              </div>
            </div>

            <div className="flex items-baseline gap-4">
              <p className="text-4xl font-black text-slate-950 tracking-tighter">
                ${product.price.toFixed(2)}
              </p>
              <span className="text-slate-400 line-through text-lg font-light">${(product.price * 1.4).toFixed(0)}</span>
            </div>

            <div className="space-y-8 bg-slate-50/50 p-8 rounded-[2.5rem] border border-slate-100">
              <div className="flex items-center justify-between">
                <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-950">Acquisition Size</span>
                <button className="text-[10px] font-bold text-blue-600 uppercase tracking-widest hover:text-blue-800 transition-colors flex items-center gap-2">
                  <Ruler className="w-3.5 h-3.5" /> Size Chart
                </button>
              </div>
              <div className="flex flex-wrap gap-4">
                {sizes.map((size) => (
                  <button 
                    key={size}
                    onClick={() => setSelectedSize(size)}
                    className={`w-16 h-16 rounded-2xl flex items-center justify-center text-sm font-black transition-all duration-300 border-2 ${selectedSize === size ? 'bg-slate-950 text-white border-slate-950 shadow-2xl scale-110' : 'bg-white text-slate-400 border-slate-100 hover:border-slate-400'}`}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Philosophy</h4>
              <p className="text-slate-600 text-lg font-light leading-relaxed">
                {product.description}
                <br/><br/>
                Every garment is a narrative of precision. Use the magnifying loupe to inspect our signature weave density and reinforced stitch work.
              </p>
            </div>

            <div className="grid grid-cols-2 gap-8 py-10 border-y border-slate-100">
              <div className="flex flex-col gap-3">
                <div className="flex items-center gap-3 text-slate-900">
                  <div className="p-2 bg-blue-50 rounded-lg"><ShieldCheck className="w-5 h-5 text-blue-600" /></div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Guarantee</span>
                </div>
                <p className="text-xs text-slate-400 leading-relaxed font-medium">Lifetime structural assurance.</p>
              </div>
              <div className="flex flex-col gap-3">
                <div className="flex items-center gap-3 text-slate-900">
                  <div className="p-2 bg-blue-50 rounded-lg"><Truck className="w-5 h-5 text-blue-600" /></div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Express</span>
                </div>
                <p className="text-xs text-slate-400 leading-relaxed font-medium">Global climate-neutral transit.</p>
              </div>
            </div>

            <div className="pt-6 space-y-4">
              <button 
                onClick={() => onAddToCart(product)}
                className="group w-full py-6 bg-slate-950 text-white rounded-[2rem] font-black text-sm uppercase tracking-[0.3em] hover:bg-blue-600 transition-all duration-500 shadow-2xl shadow-slate-950/20 flex items-center justify-center gap-4 active:scale-[0.98]"
              >
                <Plus className="w-5 h-5 group-hover:rotate-90 transition-transform" /> Add to Signature Bag
              </button>
            </div>

            <p className="text-center text-[10px] text-slate-300 font-bold uppercase tracking-[0.4em] py-4">
              Maison Artifact No. {product.id}{Math.floor(Math.random() * 1000)}
            </p>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

export default ProductModal;
